"""Fetch HTML from a URL and convert to markdown using trafilatura."""

from __future__ import annotations

from trafilatura import extract, fetch_url


def fetch_url_as_markdown(url: str) -> str:
    """Fetch the given URL and return main content as markdown.

    Args:
        url: Full URL to fetch.

    Returns:
        Markdown string. Empty string if fetch or extraction fails.
    """
    html = fetch_url(url)
    if not html:
        return ""
    result = extract(html, output_format="markdown", with_metadata=False)
    return result or ""
